import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int maxLength = 10;

        // Check if input length exceeds maxLength
        if (input.length() > maxLength) {
            System.out.println("Input exceeds maximum length of " + maxLength + ". Please enter a shorter name.");
            return;
        }

        // Copy input to buffer without exceeding buffer size
        byte[] buffer = new byte[maxLength];
        System.arraycopy(input.getBytes(), 0, buffer, 0, Math.min(input.length(), maxLength));

        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
